#nullable enable // autogenerated

using MVZ2.Vanilla.Modifiers;
using MVZ2Logic.Entities;
using PVZEngine.Buffs;
using PVZEngine.Level;
using PVZEngine.Modifiers;
using UnityEngine;

namespace MVZ2.GameContent.Buffs.Contraptions
{
    [BuffDefinition(VanillaBuffNames.Contraption.imitated)]
    public class ImitatedBuff : BuffDefinition
    {
        public ImitatedBuff(string nsp, string name) : base(nsp, name)
        {
            AddModifier(new BooleanModifier(LogicEntityProps.GRAYSCALE, true));
            AddModifier(ColorModifier.Override(LogicEntityProps.LIGHT_COLOR, Color.white, priority: VanillaModifierPriorities.FORCE));
        }
    }
}
